class ResponseScorer:
    """Evaluates candidate responses based on predefined criteria."""

    def __init__(self, scoring_criteria_file: str):
        """
        Initializes the ResponseScorer with scoring criteria loaded from a JSON file.

        Args:
            scoring_criteria_file (str): Path to the JSON file containing scoring criteria.
                                         The JSON file should have a structure like:
                                         {
                                             "question1": {
                                                 "criteria1": {"keywords": ["keyword1", "keyword2"], "score": 2},
                                                 "criteria2": {"keywords": ["keyword3"], "score": 3}
                                             },
                                             "question2": {
                                                 "criteria1": {"keywords": ["keyword4"], "keyword5"], "score": 5}
                                             }
                                         }
        """
        try:
            with open(scoring_criteria_file, 'r') as f:
                self.scoring_criteria = json.load(f)
        except FileNotFoundError:
            print(f"Error: Scoring criteria file '{scoring_criteria_file}' not found.")
            self.scoring_criteria = {}
        except json.JSONDecodeError:
            print(f"Error: Invalid JSON format in '{scoring_criteria_file}'.")
            self.scoring_criteria = {}

    def score_response(self, question: str, response: str) -> int:
        """
        Scores a candidate's response based on the predefined scoring criteria.

        Args:
            question (str): The interview question.
            response (str): The candidate's response.

        Returns:
            int: The total score for the response.
        """
        if not self.scoring_criteria:
            print("Warning: No scoring criteria loaded. Returning a default score of 0.")
            return 0

        question_criteria = self.scoring_criteria.get(question)
        if not question_criteria:
            print(f"Warning: No scoring criteria found for question '{question}'. Returning a score of 0.")
            return 0

        total_score = 0
        for criteria, details in question_criteria.items():
            keywords = details.get("keywords", [])
            score = details.get("score", 0)

            if any(keyword.lower() in response.lower() for keyword in keywords):
                total_score += score

        return total_score

    def generate_feedback(self, question: str, response: str) -> str:
        """
        Generates feedback for a candidate's response based on the scoring criteria.

        Args:
            question (str): The interview question.
            response (str): The candidate's response.

        Returns:
            str: Feedback string indicating which criteria were met or missed.
        """
        if not self.scoring_criteria:
            return "No scoring criteria loaded, so no feedback can be provided."

        question_criteria = self.scoring_criteria.get(question)
        if not question_criteria:
            return f"No scoring criteria found for question '{question}', so no feedback can be provided."

        feedback = ""
        for criteria, details in question_criteria.items():
            keywords = details.get("keywords", [])
            score = details.get("score", 0)
            met_criteria = any(keyword.lower() in response.lower() for keyword in keywords)

            if met_criteria:
                feedback += f"  - Met criteria: {criteria} (Score: {score})\n"
            else:
                feedback += f"  - Missed criteria: {criteria} (Keywords: {keywords})\n"

        return feedback

    def evaluate_interview(self, interview_data: Dict) -> Dict:
        """
        Evaluates the entire interview, scoring each response and generating feedback.

        Args:
            interview_data (Dict): A dictionary containing interview data, structured as:
                                     {
                                         "candidate_email": "email@example.com",
                                         "responses": [
                                             {"question": "Question 1", "response": "Answer 1"},
                                             {"question": "Question 2", "response": "Answer 2"}
                                         ]
                                     }

        Returns:
            Dict: A dictionary containing the evaluation report, including scores and feedback
                  for each question. The structure is as follows:
                  {
                      "candidate_email": "email@example.com",
                      "evaluation_results": [
                          {
                              "question": "Question 1",
                              "score": 3,
                              "feedback": "Feedback for Question 1"
                          },
                          {
                              "question": "Question 2",
                              "score": 5,
                              "feedback": "Feedback for Question 2"
                          }
                      ],
                      "total_score": 8
                  }
        """

        candidate_email = interview_data.get("candidate_email", "unknown")
        responses = interview_data.get("responses", [])
        evaluation_results = []
        total_score = 0

        for qa in responses:
            question = qa.get("question", "")
            response = qa.get("response", "")

            score = self.score_response(question, response)
            feedback = self.generate_feedback(question, response)

            evaluation_results.append({
                "question": question,
                "score": score,
                "feedback": feedback
            })
            total_score += score

        evaluation_report = {
            "candidate_email": candidate_email,
            "evaluation_results": evaluation_results,
            "total_score": total_score
        }

        return evaluation_report

def main():
