            {"question": "What is the difference between TCP and UDP?", "response": "TCP is connection-oriented, providing reliable data transfer, while UDP is connectionless and faster but less reliable."}
        ]
    }

    # Evaluate the interview
    evaluation_report = scorer.evaluate_interview(interview_data)

    # Print the evaluation report (or save to a file)
    print(json.dumps(evaluation_report, indent=2))

    # Example of accessing individual scores and feedback
    for result in evaluation_report["evaluation_results"]:
        print(f"Question: {result['question']}")
        print(f"Score: {result['score']}")
        print(f"Feedback:\n{result['feedback']}")

if __name__ == "__main__":
    main()
